import React, { useCallback, useEffect, useState } from "react";
import axios from "axios";
import { Link } from "react-router-dom";

const Sidebar = () => {
  const [isModalOpen, setModalState] = useState(false);
  const [projects, setProjects] = useState([]);
  const [paramsWindow, setParamsWindow] = useState(
    window.location.pathname.slice(1)
  );
  const [newProject, setNewProject] = useState({
    title: "",
    description: "",
  });

  useEffect(() => {
    projectData();
    document.addEventListener("projectUpdate", ({ detail }) => {
      projectData();
    });
    return () => {
      document.removeEventListener("projectUpdate", {}, false);
    };
  }, []);

  const handleLocation = (e) => {
    setParamsWindow(new URL(e.currentTarget.href).pathname.slice(1));
  };

  const openModal = useCallback(() => {
    setModalState(true);
  }, []);

  const closeModal = useCallback(() => {
    setModalState(false);
    setNewProject({ title: "", description: "" }); // Reset input fields
  }, []);

  const projectData = () => {
    axios.get("http://localhost:9000/projects/").then((res) => {
      setProjects(res.data);
    });
  };

  const handleAddProject = () => {
    if (newProject.title.trim() === "" || newProject.description.trim() === "") {
      alert("Please enter project name and description.");
      return;
    }

    axios.post("http://localhost:9000/projects/", newProject).then((res) => {
      setProjects([...projects, res.data]);
      closeModal();
    });
  };

  return (
    <div className="sidebar flex flex-col min-h-screen w-64 bg-gradient-to-b from-indigo-800 to-purple-900 text-white shadow-lg">
      {/* Sidebar Header */}
      <div className="sidebar-header flex items-center justify-between p-4 border-b border-gray-700">
        <span className="text-lg font-semibold">Projects</span>
        <button onClick={openModal} className="add-project-btn p-2 rounded-full bg-white bg-opacity-20 hover:bg-opacity-40 transition">
          <svg
            xmlns="http://www.w3.org/2000/svg"
            viewBox="0 0 24 24"
            fill="currentColor"
            className="w-6 h-6"
          >
            <path
              fillRule="evenodd"
              d="M12 5.25a.75.75 0 01.75.75v5.25H18a.75.75 0 010 1.5h-5.25V18a.75.75 0 01-1.5 0v-5.25H6a.75.75 0 010-1.5h5.25V6a.75.75 0 01.75-.75z"
              clipRule="evenodd"
            />
          </svg>
        </button>
      </div>

      {/* Project List */}
      <ul className="overflow-y-auto flex-1 p-2">
        {projects.map((project, index) => (
          <Link key={index} to={project._id} onClick={(e) => handleLocation(e)}>
            <li
              className={`px-5 py-2 mb-2 rounded-lg cursor-pointer transition-all 
              ${
                paramsWindow === project._id
                  ? "bg-indigo-500 text-white font-medium"
                  : "text-gray-300 hover:bg-indigo-600 hover:text-white"
              }`}
            >
              {project.title}
            </li>
          </Link>
        ))}
      </ul>

      {/* Add Project Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex justify-center items-center">
          <div className="bg-white p-6 rounded-lg shadow-xl w-96">
            <h2 className="text-lg font-semibold text-gray-800 mb-4">Add Project</h2>
            <input
              type="text"
              placeholder="Project Name"
              className="w-full p-2 border border-gray-300 rounded mb-3"
              value={newProject.title}
              onChange={(e) =>
                setNewProject({ ...newProject, title: e.target.value })
              }
            />
            <textarea
              placeholder="Project Description"
              className="w-full p-2 border border-gray-300 rounded mb-3"
              rows="3"
              value={newProject.description}
              onChange={(e) =>
                setNewProject({ ...newProject, description: e.target.value })
              }
            />
            <div className="flex justify-end space-x-2">
              <button
                onClick={closeModal}
                className="px-4 py-2 bg-gray-300 text-gray-800 rounded hover:bg-gray-400"
              >
                Cancel
              </button>
              <button
                onClick={handleAddProject}
                className="px-4 py-2 bg-indigo-600 text-white rounded hover:bg-indigo-700"
              >
                Add
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Sidebar;
